1	import {
2	  quote,
3	  claim,
4	  insuranceValueFor,
5	  isKnownItemType,
6	  type Customer,
7	  type Item,
8	  type Policy,
9	  type Incident,
10	} from "./claim-office.js";
11	
12	const CAP_MULTIPLIER = 2;
13	
14	type QuoteStep = {
15	  op: "quote";
16	  items: Item[];
17	};
18	
19	type ClaimStep = {
20	  op: "claim";
21	  policy: number;
22	  incident: Incident;
23	};
24	
25	type Step = QuoteStep | ClaimStep;
26	
27	type Scenario = {
28	  customer: Customer;
29	  steps: Step[];
30	};
31	
32	const readStdin = async (): Promise<string> => {
33	  const chunks: Buffer[] = [];
34	  for await (const chunk of process.stdin) {
35	    chunks.push(chunk as Buffer);
36	  }
37	  return Buffer.concat(chunks).toString("utf8");
38	};
39	
40	const policyCapFor = (items: Item[]): number =>
41	  items.reduce((sum, item) => sum + CAP_MULTIPLIER * insuranceValueFor(item), 0);
42	
43	const handleQuote = (
44	  customer: Customer,
45	  step: QuoteStep,
46	  policies: Policy[],
47	): unknown => {
48	  const unknown = step.items.find((item) => !isKnownItemType(item.type));
49	  if (unknown) throw new Error(`Unknown item type: ${unknown.type}`);
50	  const result = quote({ customer, items: step.items });
51	  policies.push({ items: step.items, remainingCap: policyCapFor(step.items) });
52	  return result;
53	};
54	
55	const handleClaim = (step: ClaimStep, policies: Policy[]): unknown => {
56	  const policy = policies[step.policy];
57	  const uncovered = step.incident.damages.find(
58	    (damage) => !policy.items.some((item) => item.type === damage.itemType),
59	  );
60	  if (uncovered) throw new Error(`Damage references item not in policy: ${uncovered.itemType}`);
61	  const result = claim({ policy, incident: step.incident });
62	  policy.remainingCap = result.remainingCap;
63	  return result;
64	};
65	
66	const runStep = (
67	  customer: Customer,
68	  step: Step,
69	  policies: Policy[],
70	): unknown =>
71	  step.op === "quote"
72	    ? handleQuote(customer, step, policies)
73	    : handleClaim(step, policies);
74	
75	const runScenario = (scenario: Scenario): unknown[] => {
76	  const policies: Policy[] = [];
77	  return scenario.steps.map((step) => runStep(scenario.customer, step, policies));
78	};
79	
80	const main = async () => {
81	  const input = await readStdin();
82	  const scenario: Scenario = JSON.parse(input);
83	  const results = runScenario(scenario);
84	  process.stdout.write(JSON.stringify({ results }));
85	};
86	
87	main().catch((err) => {
88	  process.stderr.write(String(err));
89	  process.exit(1);
90	});
